mapper.select:
SELECT COUNT(1)
FROM study_plan
WHERE user_id = #{userId}
  AND deleted_flag = 0
  AND plan_date >= #{startDate}
  AND plan_date <= #{endDate}

SELECT COUNT(1)
FROM study_plan
WHERE user_id = #{userId}
  AND deleted_flag = 0
  AND plan_status = 2
  AND plan_date >= #{startDate}
  AND plan_date <= #{endDate}

SELECT COUNT(DISTINCT record_date)
FROM life_record
WHERE user_id = #{userId}
  AND deleted_flag = 0
  AND record_date >= #{startDate}
  AND record_date <= #{endDate}

SELECT COUNT(DISTINCT review_date)
FROM daily_review
WHERE user_id = #{userId}
  AND deleted_flag = 0
  AND review_date >= #{startDate}
  AND review_date <= #{endDate}

SELECT plan_date AS date,
       COUNT(1) AS plan_count,
       SUM(CASE WHEN plan_status = 2 THEN 1 ELSE 0 END) AS completed_plan_count
FROM study_plan
WHERE user_id = #{userId}
  AND deleted_flag = 0
  AND plan_date >= #{startDate}
  AND plan_date <= #{endDate}
GROUP BY plan_date
ORDER BY plan_date ASC

SELECT plan_status,
       COUNT(1) AS count
FROM study_plan
WHERE user_id = #{userId}
  AND deleted_flag = 0
  AND plan_date >= #{startDate}
  AND plan_date <= #{endDate}
GROUP BY plan_status
ORDER BY plan_status ASC

SELECT plan_date AS date,
       COUNT(1) AS plan_count,
       SUM(CASE WHEN plan_status = 2 THEN 1 ELSE 0 END) AS completed_plan_count
FROM study_plan
WHERE user_id = #{userId}
  AND deleted_flag = 0
  AND plan_date >= #{startDate}
  AND plan_date <= #{endDate}
GROUP BY plan_date
ORDER BY plan_date ASC
